function clearCollectorRefresh(){if(collectorRefreshTimer){window.clearTimeout(collectorRefreshTimer);collectorRefreshTimer=0;}}
function syncCollectorRefresh(){clearCollectorRefresh();const environmentId=currentEnvironmentId();if(!environmentId)return;const job=((state.dashboard||{}).job)||{};const shouldPoll=job.status==="running"||collectorRefreshWindowActive(environmentId);if(shouldPoll)collectorRefreshTimer=window.setTimeout(function(){loadAllData(false);},2500);}
function clearUpgradeRefresh(){if(upgradeRefreshTimer){window.clearTimeout(upgradeRefreshTimer);upgradeRefreshTimer=0;}}
async function pollUpgradeStatus(){if(!upgradeRefreshWindowActive()&&!githubUpgradeBusy(selectedGithubUpgrade().status.status))return;try{const result=await fetchJson("/api/admin/upgrade/status");if(state.appShell&&state.appShell.help)state.appShell.help.githubUpgrade=normalizeGithubUpgradeMeta(result);const upgrade=selectedGithubUpgrade();if(!githubUpgradeBusy(upgrade.status.status)){stopUpgradeRefreshWindow();if(upgrade.status.status==="completed"){await loadAllData(false);setMessage(`GitHub upgrade completed on ${formatValue(upgrade.status.currentVersion,currentVersion())}.`,"success");return;}if(upgrade.status.status==="failed"){setMessage(upgrade.status.lastError||upgrade.status.message||"GitHub upgrade failed.","error");}}render();}catch(error){if(state.appShell&&state.appShell.help&&upgradeRefreshWindowActive()){const current=selectedGithubUpgrade();state.appShell.help.githubUpgrade=normalizeGithubUpgradeMeta(Object.assign({},current,{status:Object.assign({},current.status,{status:"reconnecting",message:"The dashboard is restarting during the GitHub upgrade. Waiting for it to come back."})}));render();}}finally{syncUpgradeRefresh();}}
function syncUpgradeRefresh(){clearUpgradeRefresh();const upgrade=selectedGithubUpgrade();if(githubUpgradeBusy(upgrade.status.status)||upgradeRefreshWindowActive())upgradeRefreshTimer=window.setTimeout(function(){pollUpgradeStatus();},2500);}
function scheduleCollectorRefresh(environmentId){startCollectorRefreshWindow(environmentId||currentEnvironmentId());syncCollectorRefresh();}
async function runBootstrap(environmentId,environmentName){const result=await fetchJson(`/api/admin/environments/${encodeURIComponent(environmentId)}/bootstrap`,{method:"POST"});let message=`Bootstrap completed for ${environmentName||"the environment"}.`;if(result.collectorJobStarted)message+=" Collector started.";else if(result.collectorJobAlreadyRunning)message+=" Collector was already running.";setMessage(message,"success");startCollectorRefreshWindow(environmentId);await loadAllData(false);scheduleCollectorRefresh(environmentId);return result;}
async function runJobsNow(environmentId,environmentName){const previousJob=state.dashboard&&state.dashboard.job?Object.assign({},state.dashboard.job):null;optimisticCollectorStart(environmentId,environmentName,"Run Jobs Now requested from the dashboard. Waiting for collector startup.");try{const result=await fetchJson(`/api/admin/environments/${encodeURIComponent(environmentId)}/jobs/run`,{method:"POST"});let message=`Collector started for ${environmentName||"the environment"}.`;if(result.collectorJobAlreadyRunning)message=`Collector is already running for ${environmentName||"the environment"}.`;setMessage(message,"success");startCollectorRefreshWindow(environmentId);await loadAllData(false);scheduleCollectorRefresh(environmentId);return result;}catch(error){if(state.dashboard)state.dashboard.job=previousJob||state.dashboard.job;render();throw error;}}
async function runGithubUpgrade(){const result=await fetchJson("/api/admin/upgrade/run",{method:"POST"});if(state.appShell&&state.appShell.help)state.appShell.help.githubUpgrade=normalizeGithubUpgradeMeta(result.upgrade);startUpgradeRefreshWindow();setMessage("GitHub upgrade queued. The dashboard will disconnect briefly while the service restarts.","info");render();syncUpgradeRefresh();return result;}
async function saveEnvironment(runBootstrapAfterSave){const editingId=state.editingEnvironmentId;const payload=readEnvironmentForm();const result=await fetchJson(editingId?`/api/admin/environments/${encodeURIComponent(editingId)}`:"/api/admin/environments",{method:editingId?"PUT":"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)});const environment=result.environment||{};state.environmentModalOpen=false;state.editingEnvironmentId=null;state.lastEnvironmentId=environment.id||state.lastEnvironmentId;await loadAllData(false);if(runBootstrapAfterSave&&environment.id){await runBootstrap(environment.id,environment.name||payload.name);return;}setMessage(`Environment ${environment.name||payload.name} saved.`,"success");}
async function deleteEnvironment(environmentId){if(!window.confirm("Delete this environment from the dashboard?"))return;await fetchJson(`/api/admin/environments/${encodeURIComponent(environmentId)}`,{method:"DELETE"});if(state.activeContext===environmentId){state.activeContext="administration";state.activeSection="admin-environments";}if(state.lastEnvironmentId===environmentId)state.lastEnvironmentId=null;if(state.editingEnvironmentId===environmentId){state.editingEnvironmentId=null;state.environmentModalOpen=false;}setMessage("Environment deleted.","success");await loadAllData(false);}
async function saveNotificationSettings(form){const payload={smtpHost:String(form.elements.smtpHost.value||"").trim(),smtpPort:parseInt(form.elements.smtpPort.value,10)||587,smtpUsername:String(form.elements.smtpUsername.value||"").trim(),smtpPassword:String(form.elements.smtpPassword.value||""),senderName:String(form.elements.senderName.value||"").trim(),senderEmail:String(form.elements.senderEmail.value||"").trim(),securityMode:String(form.elements.securityMode.value||"starttls").trim(),enabled:Boolean(form.elements.enabled.checked)};const result=await fetchJson("/api/admin/notifications/settings",{method:"PUT",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)});state.notifications=state.notifications||{};state.notifications.settings=normalizeNotificationSettings(result.settings);state.notifications.recipients=coerceList((state.notifications||{}).recipients);setMessage("SMTP settings saved.","success");render();}
async function saveUpdateProxySettings(form,runCheckAfterSave){const payload={httpProxy:String(form.elements.httpProxy.value||"").trim(),httpsProxy:String(form.elements.httpsProxy.value||"").trim(),noProxy:String(form.elements.noProxy.value||"").trim()};await fetchJson("/api/admin/help/proxy",{method:"PUT",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)});await loadAllData(false);if(runCheckAfterSave){setMessage("GitHub proxy saved. Rechecking GitHub now.","info");await checkForUpdates();return;}setMessage("GitHub proxy settings saved.","success");}
async function sendNotificationTest(form){const payload={targetEmail:String(form.elements.targetEmail.value||"").trim()};const result=await fetchJson("/api/admin/notifications/test",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)});setMessage(`Test email sent to ${result.targetEmail}.`,"success");}
async function saveRecipient(form){const payload={id:String(form.elements.id.value||"").trim()||undefined,name:String(form.elements.name.value||"").trim(),email:String(form.elements.email.value||"").trim(),severity:String(form.elements.severity.value||"any").trim(),enabled:Boolean(form.elements.enabled.checked)};const result=await fetchJson("/api/admin/notifications/recipients",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)});state.notifications=state.notifications||{};state.notifications.settings=normalizeNotificationSettings((state.notifications||{}).settings);state.notifications.recipients=coerceList(result.recipients);state.editingRecipientId=null;setMessage(`Recipient ${payload.name} saved.`,"success");render();}
async function deleteRecipient(recipientId){if(!window.confirm("Delete this recipient?"))return;const result=await fetchJson(`/api/admin/notifications/recipients/${encodeURIComponent(recipientId)}`,{method:"DELETE"});state.notifications=state.notifications||{};state.notifications.settings=normalizeNotificationSettings((state.notifications||{}).settings);state.notifications.recipients=coerceList(result.recipients);state.editingRecipientId=null;setMessage("Recipient deleted.","success");render();}
async function checkForUpdates(){if(state.isCheckingUpdates)return;syncUpdateCheckVersion();state.isCheckingUpdates=true;state.updateCheck=Object.assign({},state.updateCheck||{currentVersion:currentVersion()},{status:"checking",message:"Checking GitHub for updates..."});renderUpdateCheckStatus();try{const result=await fetchJson("/api/admin/updates/check");state.updateCheck=result;if(result.status==="update_available")setMessage(`Update available on GitHub: ${result.remoteVersion}.`,"info");else if(result.status==="current")setMessage(`This dashboard is up to date on ${result.currentVersion}.`,"success");else if(result.status==="ahead")setMessage(`This dashboard is ahead of GitHub ${result.branch||"main"} on ${result.currentVersion}.`,"info");else if(result.status==="different")setMessage(result.message||"GitHub reports a different version for this dashboard.","info");else if(result.status==="error")setMessage(result.message||"GitHub update check failed.","error");}catch(error){state.updateCheck={status:"error",currentVersion:currentVersion(),remoteVersion:"",message:error.message,checkedAt:""};setMessage(error.message,"error");}finally{state.isCheckingUpdates=false;renderUpdateCheckStatus();}}
function openEnvironmentModal(environmentId){clearMessage();state.environmentModalOpen=true;state.editingEnvironmentId=environmentId||null;renderEnvironmentModal();}
function closeEnvironmentModal(){state.environmentModalOpen=false;state.editingEnvironmentId=null;renderEnvironmentModal();}
function renderPageContent(){if(!state.appShell)return renderEmptyPanel("Loading console","The dashboard is fetching its current state.");if(isAdministrationContext()){if(state.activeSection==="admin-notifications")return renderNotificationsPage();if(state.activeSection==="admin-help")return renderHelpPage();return renderEnvironmentRegistryPage();}if(!state.dashboard)return renderEmptyPanel("Loading environment","The selected environment dashboard is still being collected.");if(state.activeSection==="env-overview-operations")return renderOperationsPage();if(state.activeSection==="env-server")return renderServerMetricsPage();if(state.activeSection==="env-applications")return renderApplicationMetricsPage();return renderOverviewPage();}
function render(){renderContextSwitcher();renderUpdateCheckStatus();renderSidebar();renderHeader();renderMessage();refs.pageContent.innerHTML=renderPageContent();renderEnvironmentModal();syncCollectorRefresh();syncUpgradeRefresh();}
async function changeContext(context){clearMessage();clearCollectorRefresh();stopCollectorRefreshWindow();state.activeContext=context||"administration";state.activeSection=defaultSectionForContext(state.activeContext);if(state.activeContext!=="administration"){state.lastEnvironmentId=state.activeContext;ensureNavGroupOpenForSection(state.activeSection);}persistState();await loadAllData(false);}
document.addEventListener("click",async function(event){const checkUpdatesButton=event.target.closest("[data-check-updates]");if(checkUpdatesButton){try{await checkForUpdates();}catch(error){return;}return;}const navGroupToggle=event.target.closest("[data-nav-group-toggle]");if(navGroupToggle){const groupId=navGroupToggle.getAttribute("data-nav-group-toggle");state.navGroups=normalizeEnvironmentNavGroups(state.navGroups);state.navGroups[groupId]=!state.navGroups[groupId];persistState();render();return;}const sectionButton=event.target.closest("[data-section]");if(sectionButton){state.activeSection=normalizeSectionForContext(state.activeContext,sectionButton.getAttribute("data-section"));if(!isAdministrationContext())ensureNavGroupOpenForSection(state.activeSection);persistState();render();return;}const openEnvironmentButton=event.target.closest("[data-open-environment]");if(openEnvironmentButton){await changeContext(openEnvironmentButton.getAttribute("data-open-environment"));return;}const createEnvironmentButton=event.target.closest("[data-create-environment]");if(createEnvironmentButton){openEnvironmentModal(null);return;}const editEnvironmentButton=event.target.closest("[data-edit-environment]");if(editEnvironmentButton){openEnvironmentModal(editEnvironmentButton.getAttribute("data-edit-environment"));return;}const deleteEnvironmentButton=event.target.closest("[data-delete-environment]");if(deleteEnvironmentButton){try{await deleteEnvironment(deleteEnvironmentButton.getAttribute("data-delete-environment"));}catch(error){setMessage(error.message,"error");}return;}const saveAndBootstrapButton=event.target.closest("[data-save-and-bootstrap]");if(saveAndBootstrapButton){try{await saveEnvironment(true);}catch(error){setMessage(error.message,"error");}return;}const runBootstrapButton=event.target.closest("[data-run-bootstrap]");if(runBootstrapButton){const current=selectedEnvironmentRecord()||selectedEnvironmentOverview()||{};try{await runBootstrap(current.id,current.name);}catch(error){setMessage(error.message,"error");}return;}const runJobsButton=event.target.closest("[data-run-jobs]");if(runJobsButton){const current=selectedEnvironmentRecord()||selectedEnvironmentOverview()||{};try{await runJobsNow(current.id,current.name);}catch(error){setMessage(error.message,"error");}return;}const runGithubUpgradeButton=event.target.closest("[data-run-github-upgrade]");if(runGithubUpgradeButton){try{await runGithubUpgrade();}catch(error){setMessage(error.message,"error");}return;}const editRecipientButton=event.target.closest("[data-edit-recipient]");if(editRecipientButton){state.editingRecipientId=editRecipientButton.getAttribute("data-edit-recipient");render();return;}const deleteRecipientButton=event.target.closest("[data-delete-recipient]");if(deleteRecipientButton){try{await deleteRecipient(deleteRecipientButton.getAttribute("data-delete-recipient"));}catch(error){setMessage(error.message,"error");}return;}const resetRecipientButton=event.target.closest("[data-reset-recipient]");if(resetRecipientButton){state.editingRecipientId=null;render();return;}const productTabButton=event.target.closest("[data-product-tab]");if(productTabButton){state.activeProductTab=productTabButton.getAttribute("data-product-tab");persistState();render();return;}const closeModalButton=event.target.closest("[data-close-modal]");if(closeModalButton||event.target===refs.environmentModalClose){closeEnvironmentModal();}});
document.addEventListener("click",async function(event){const saveProxyAndCheckButton=event.target.closest("[data-save-proxy-and-check]");if(!saveProxyAndCheckButton)return;const form=document.getElementById("update-proxy-form");if(!form)return;try{await saveUpdateProxySettings(form,true);}catch(error){setMessage(error.message,"error");}});
document.addEventListener("submit",async function(event){if(event.target&&event.target.id==="environment-form"){event.preventDefault();try{await saveEnvironment(false);}catch(error){setMessage(error.message,"error");}return;}if(event.target&&event.target.id==="notification-settings-form"){event.preventDefault();try{await saveNotificationSettings(event.target);}catch(error){setMessage(error.message,"error");}return;}if(event.target&&event.target.id==="update-proxy-form"){event.preventDefault();try{await saveUpdateProxySettings(event.target,false);}catch(error){setMessage(error.message,"error");}return;}if(event.target&&event.target.id==="notification-test-form"){event.preventDefault();try{await sendNotificationTest(event.target);}catch(error){setMessage(error.message,"error");}return;}if(event.target&&event.target.id==="recipient-form"){event.preventDefault();try{await saveRecipient(event.target);}catch(error){setMessage(error.message,"error");}}});
document.addEventListener("change",function(event){if(event.target===refs.contextSwitcher){changeContext(refs.contextSwitcher.value);return;}if(event.target&&(event.target.name==="environmentType"||event.target.name==="serverSshMode"||event.target.name==="collectionEnabled"||event.target.name==="withWeblogic"||event.target.name==="weblogicAdminHostSshMode"))syncEnvironmentFormDisplay();});
